+
+    #[test]
+    fn first_ok_error_debug_clone() {
+        let e: FirstOkError<&str> = FirstOkError::AllFailed {
+            errors: vec!["e1", "e2"],
+            attempted: 2,
+        };
+        let e2 = e.clone();
